+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
?/g, '\
');
+}
+
+function isInternalFrame(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']) {
+  return (
+    (mode === 'node' || mode === 'node_and_superjson') && line.includes('node:internal') ||
+    (mode === 'superjson' || mode === 'node_and_superjson') &&
+      (line.includes('src/transformer.ts') || line.includes('src/plainer.ts') || line.includes('src/index.ts'))
+  );
+}
+
+function redactPaths(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
+  if (mode === 'strip_cwd') {
+    const cwd = process.cwd().replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&');
+    return line.replace(new RegExp(cwd.replace(/\\\\/g, '[\\\\\\\\/]'), 'g'), '');
+  }
+  if (mode === 'basename') {
+    return line.replace(/(?:[A-Za-z]:[\\\\/]|\\/)[^\\s():]+(?:[\\\\/][^\\s():]+)*/g, path => {
+      const parts = path.split(/[\\\\/]/);
+      return parts[parts.length - 1];
+    });
+  }
+  return line;
+}
+
+function processLines(stack: string, options: NormalizedErrorStackOptions, framesOrder: boolean): string[] {
+  let lines = (options.normalizeNewlines ? normalizeStackNewlines(stack) : stack).split('\
');
+  if (options.trimLeadingWhitespace) lines = lines.map((line, i) => i === 0 ? line : line.replace(/^\\s+/, ''));
+  if (framesOrder) lines = [lines[0], ...lines.slice(1).filter(line => !isInternalFrame(line, options.stripInternalFrames))];
+  if (!framesOrder) lines = lines.map(line => redactPaths(line, options.redactPaths));
+  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
+  if (!framesOrder) lines = [lines[0], ...lines.slice(1).filter(line => !isInternalFrame(line, options.stripInternalFrames))];
+  if (framesOrder) lines = lines.map(line => redactPaths(line, options.redactPaths));
+  return lines;
+}
+
+export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
+  return processLines(stack, options, false).join('\
');
+}
+
+export function processStackFrames(stack: string, options: NormalizedErrorStackOptions): Array<{ raw: string }> {
+  return processLines(stack, options, true).map(raw => ({ raw }));
+}
