+function serializeError(
+  error: Error,
+  superJson: SuperJSON,
+  annotation: 'Error' | 'Error/stack' | 'Error/frames'
+) {
+  const options = superJson.errorStackOptions;
+  const matches = !options?.classFilter || options.classFilter.includes(error.name);
+  const baseError: Record<string, any> = {
+    name: error.name,
+    message:
+      options?.sanitizeMessage && matches
+        ? sanitizeMessage(error.message)
+        : error.message,
+  };
+
+  if (!options) {
+    if ('cause' in error) baseError.cause = (error as any).cause;
+  } else if (options.includeCauses !== 'none') {
+    const remainingDepth = superJson.getErrorCauseDepth(error);
+    const cause = (error as any).cause;
+    if (remainingDepth > 0 && cause instanceof Error) {
+      superJson.setErrorCauseDepth(cause, remainingDepth - 1);
+      baseError.cause = cause;
+    }
+  }
+
+  if (typeof AggregateError !== 'undefined' && error instanceof AggregateError) {
+    baseError.errors = error.errors;
+  }
+
+  superJson.allowedErrorProps.forEach(prop => {
+    if (options && (prop === 'stack' || prop === 'stackFrames')) return;
+    baseError[prop] = (error as any)[prop];
+  });
+
+  if (annotation === 'Error/stack' && superJson.allowedErrorProps.includes('stack')) {
+    baseError.stack = processStackString(error.stack ?? '', options!);
+  }
+  if (
+    annotation === 'Error/frames' &&
+    superJson.allowedErrorProps.includes('stackFrames')
+  ) {
+    baseError.stackFrames = processStackFrames(error.stack ?? '', options!);
+  }
+
+  const processor = superJson.errorClassRegistry.getProcessor(error.name);
+  return processor ? processor(baseError) : baseError;
